import { useState } from "react";
import { useNavigate } from "react-router-dom";


const baseRates = {
  "Corporate Meeting": 18000,
  "Birthday Party": 22000,
  "Wedding Reception": 65000,
  "Private Dinner": 16000,
  "Family Celebration": 28000,
};

const EventBooking = () => {
  const navigate = useNavigate();

  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [event_date, setEvent_date] = useState("");
  const [event_type, setEvent_type] = useState("Corporate Meeting");
  const [guests, setGuests] = useState("");

  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState("");
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");
    setSuccess("");

    const guestCount = Number(guests) || 0;
    const estimatedPrice =
      (baseRates[event_type] || 15000) + guestCount * 850;

    const payload = {
      name,
      email,
      phone,
      event_date,
      event_type,
      guests: guestCount,
      message: `${event_type} booking request for ${guestCount} guest(s).`,
    };

    console.log("Sending payload:", payload); // DEBUG

    try {
      const response = await submitEventBooking(payload);

      setSuccess(
        response?.data?.message || "Event request sent successfully."
      );

      // Navigate to payment
      navigate("/makepayment", {
        state: {
          checkoutItem: {
            title: `${event_type} Event Booking`,
            description: `Name: ${name} | Email: ${email} | Phone: ${phone} | Guests: ${guestCount} | Event Date: ${event_date}`,
            amount: estimatedPrice,
            type: "Event Booking",
            image:
              "https://images.unsplash.com/photo-1519167758481-83f550bb49b3?auto=format&fit=crop&w=1200&q=80",
          },
          paymentNotice:
            "Your event request was saved successfully. Complete payment below.",
        },
      });

      // Reset form
      setName("");
      setEmail("");
      setPhone("");
      setEvent_date("");
      setEvent_type("Corporate Meeting");
      setGuests("");

    } catch (err) {
      console.error("API Error:", err?.response || err.message);

      // If server not reachable â†’ still allow payment
      if (!err.response) {
        navigate("/makepayment", {
          state: {
            checkoutItem: {
              title: `${event_type} Event Booking`,
              description: `Name: ${name} | Email: ${email} | Phone: ${phone} | Guests: ${guestCount} | Event Date: ${event_date}`,
              amount: estimatedPrice,
              type: "Event Booking",
              image:
                "https://images.unsplash.com/photo-1519167758481-83f550bb49b3?auto=format&fit=crop&w=1200&q=80",
            },
            paymentNotice:
              "Server not reachable. You can still continue with payment.",
          },
        });
        return;
      }

      setError(
        err.response?.data?.message || "Failed to send booking request"
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        placeholder="Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
        required
      />

      <input
        type="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
      />

      <input
        placeholder="Phone"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
        required
      />

      <input
        type="date"
        value={event_date}
        onChange={(e) => setEvent_date(e.target.value)}
        required
      />

      {/* âś… FIXED: dropdown instead of input */}
      <select
        value={event_type}
        onChange={(e) => setEvent_type(e.target.value)}
      >
        {Object.keys(baseRates).map((type) => (
          <option key={type} value={type}>
            {type}
          </option>
        ))}
      </select>

      <input
        type="number"
        placeholder="Number of Guests"
        value={guests || ""}
        onChange={(e) => setGuests(e.target.value)}
        required
      />

      <button type="submit">
        {loading ? "Sending..." : "Send Event Request"}
      </button>

      {success && <p style={{ color: "green" }}>{success}</p>}
      {error && <p style={{ color: "red" }}>{error}</p>}
    </form>
  );
};

export default EventBooking;
